CREATE TYPE "DataConnectorDomain" AS ENUM ('HRIS','CRM','ERP','PROJECT','COLLABORATION','PRODUCTIVITY','CUSTOM');
CREATE TYPE "DataConnectionStatus" AS ENUM ('DRAFT','ACTIVE','PAUSED','ERROR','DISABLED');
CREATE TYPE "DataSyncDirection" AS ENUM ('INBOUND','OUTBOUND','BIDIRECTIONAL');
CREATE TYPE "DataSyncTrigger" AS ENUM ('MANUAL','SCHEDULED','EVENT');
CREATE TYPE "DataSyncRunStatus" AS ENUM ('PENDING','RUNNING','SUCCEEDED','PARTIAL','FAILED','CANCELLED');
CREATE TYPE "DataSyncRecordStatus" AS ENUM ('PENDING','CREATED','UPDATED','SKIPPED','FAILED','CONFLICT');
CREATE TYPE "DataConflictPolicy" AS ENUM ('SOURCE_WINS','TARGET_WINS','LATEST_WINS','MANUAL');
CREATE TYPE "DataConflictStatus" AS ENUM ('OPEN','RESOLVED','IGNORED');
CREATE TABLE "DataConnectorDefinition" ("id" TEXT PRIMARY KEY,"key" TEXT NOT NULL UNIQUE,"name" TEXT NOT NULL,"domain" "DataConnectorDomain" NOT NULL,"description" TEXT,"capabilities" TEXT[] NOT NULL,"supportedObjects" TEXT[] NOT NULL,"configurationSchema" JSONB,"active" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "DataConnection" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"connectorDefinitionId" TEXT NOT NULL,"name" TEXT NOT NULL,"status" "DataConnectionStatus" NOT NULL DEFAULT 'DRAFT',"baseUrl" TEXT,"tenantKey" TEXT,"encryptedCredential" TEXT,"credentialFingerprint" TEXT,"credentialExpiresAt" TIMESTAMP(3),"settings" JSONB,"lastHealthCheckAt" TIMESTAMP(3),"lastSuccessfulSyncAt" TIMESTAMP(3),"createdByUserId" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "DataConnection_connectorDefinitionId_fkey" FOREIGN KEY ("connectorDefinitionId") REFERENCES "DataConnectorDefinition"("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE UNIQUE INDEX "DataConnection_organizationId_name_key" ON "DataConnection"("organizationId","name"); CREATE INDEX "DataConnection_organizationId_status_idx" ON "DataConnection"("organizationId","status");
CREATE TABLE "DataSyncDefinition" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"connectionId" TEXT NOT NULL,"name" TEXT NOT NULL,"sourceObject" TEXT NOT NULL,"targetEntity" TEXT NOT NULL,"direction" "DataSyncDirection" NOT NULL DEFAULT 'INBOUND',"trigger" "DataSyncTrigger" NOT NULL DEFAULT 'MANUAL',"scheduleCron" TEXT,"conflictPolicy" "DataConflictPolicy" NOT NULL DEFAULT 'MANUAL',"enabled" BOOLEAN NOT NULL DEFAULT true,"filter" JSONB,"checkpoint" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "DataSyncDefinition_connectionId_fkey" FOREIGN KEY ("connectionId") REFERENCES "DataConnection"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE UNIQUE INDEX "DataSyncDefinition_connectionId_name_key" ON "DataSyncDefinition"("connectionId","name"); CREATE INDEX "DataSyncDefinition_organizationId_enabled_idx" ON "DataSyncDefinition"("organizationId","enabled");
CREATE TABLE "DataFieldMapping" ("id" TEXT PRIMARY KEY,"syncDefinitionId" TEXT NOT NULL,"sourceField" TEXT NOT NULL,"targetField" TEXT NOT NULL,"transform" JSONB,"defaultValue" JSONB,"required" BOOLEAN NOT NULL DEFAULT false,"sensitive" BOOLEAN NOT NULL DEFAULT false,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "DataFieldMapping_syncDefinitionId_fkey" FOREIGN KEY ("syncDefinitionId") REFERENCES "DataSyncDefinition"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE UNIQUE INDEX "DataFieldMapping_syncDefinitionId_sourceField_targetField_key" ON "DataFieldMapping"("syncDefinitionId","sourceField","targetField");
CREATE TABLE "DataSyncRun" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"connectionId" TEXT NOT NULL,"syncDefinitionId" TEXT NOT NULL,"status" "DataSyncRunStatus" NOT NULL DEFAULT 'PENDING',"trigger" "DataSyncTrigger" NOT NULL,"correlationId" TEXT NOT NULL,"checkpointBefore" JSONB,"checkpointAfter" JSONB,"recordsRead" INTEGER NOT NULL DEFAULT 0,"recordsCreated" INTEGER NOT NULL DEFAULT 0,"recordsUpdated" INTEGER NOT NULL DEFAULT 0,"recordsSkipped" INTEGER NOT NULL DEFAULT 0,"recordsFailed" INTEGER NOT NULL DEFAULT 0,"conflictsFound" INTEGER NOT NULL DEFAULT 0,"errorMessage" TEXT,"startedAt" TIMESTAMP(3),"completedAt" TIMESTAMP(3),"triggeredByUserId" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "DataSyncRun_connectionId_fkey" FOREIGN KEY ("connectionId") REFERENCES "DataConnection"("id") ON DELETE CASCADE ON UPDATE CASCADE,CONSTRAINT "DataSyncRun_syncDefinitionId_fkey" FOREIGN KEY ("syncDefinitionId") REFERENCES "DataSyncDefinition"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE INDEX "DataSyncRun_organizationId_status_createdAt_idx" ON "DataSyncRun"("organizationId","status","createdAt"); CREATE INDEX "DataSyncRun_syncDefinitionId_createdAt_idx" ON "DataSyncRun"("syncDefinitionId","createdAt");
CREATE TABLE "DataSyncRecord" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"syncRunId" TEXT NOT NULL,"externalId" TEXT NOT NULL,"internalEntityId" TEXT,"status" "DataSyncRecordStatus" NOT NULL DEFAULT 'PENDING',"sourceChecksum" TEXT,"targetChecksum" TEXT,"sourceUpdatedAt" TIMESTAMP(3),"targetUpdatedAt" TIMESTAMP(3),"payloadSummary" JSONB,"errorMessage" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "DataSyncRecord_syncRunId_fkey" FOREIGN KEY ("syncRunId") REFERENCES "DataSyncRun"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE UNIQUE INDEX "DataSyncRecord_syncRunId_externalId_key" ON "DataSyncRecord"("syncRunId","externalId"); CREATE INDEX "DataSyncRecord_organizationId_status_updatedAt_idx" ON "DataSyncRecord"("organizationId","status","updatedAt");
CREATE TABLE "DataSyncConflict" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"syncDefinitionId" TEXT NOT NULL,"externalId" TEXT NOT NULL,"internalEntityId" TEXT,"field" TEXT NOT NULL,"sourceValue" JSONB,"targetValue" JSONB,"policy" "DataConflictPolicy" NOT NULL,"status" "DataConflictStatus" NOT NULL DEFAULT 'OPEN',"resolution" "DataConflictPolicy","resolvedByUserId" TEXT,"resolvedAt" TIMESTAMP(3),"notes" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "DataSyncConflict_syncDefinitionId_fkey" FOREIGN KEY ("syncDefinitionId") REFERENCES "DataSyncDefinition"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE INDEX "DataSyncConflict_organizationId_status_createdAt_idx" ON "DataSyncConflict"("organizationId","status","createdAt");
